manifest_content:
{
  "name": "caveman-installer",
  "version": "0.1.0",
  "description": "Caveman installer — detects your AI coding agents and installs caveman for each one.",
  "license": "MIT",
  "author": "Julius Brussee",
  "homepage": "https://github.com/JuliusBrussee/caveman",
  "repository": {
    "type": "git",
    "url": "git+https://github.com/JuliusBrussee/caveman.git"
  },
  "bugs": {
    "url": "https://github.com/JuliusBrussee/caveman/issues"
  },
  "bin": {
    "caveman": "./bin/install.js"
  },
  "engines": {
    "node": ">=18"
  },
  "scripts": {
    "test": "node --test tests/installer/*.test.mjs"
  },
  "files": [
    "bin/",
    "src/",
    "agents/",
    "skills/",
    "plugins/",
    "commands/",
    "dist/caveman.skill",
    "README.md",
    "LICENSE"
  ]
}

{
  "name": "tradingview-mcp",
  "version": "1.0.0",
  "description": "MCP bridge for TradingView Desktop via Chrome DevTools Protocol",
  "type": "module",
  "main": "src/server.js",
  "bin": {
    "tv": "src/cli/index.js"
  },
  "exports": {
    ".": "./src/server.js",
    "./core": "./src/core/index.js"
  },
  "scripts": {
    "start": "node src/server.js",
    "tv": "node src/cli/index.js",
    "lint": "eslint src/",
    "test": "node --test tests/e2e.test.js tests/pine_analyze.test.js",
    "test:e2e": "node --test tests/e2e.test.js",
    "test:unit": "node --test tests/pine_analyze.test.js tests/cli.test.js tests/sanitization.test.js tests/replay.test.js tests/launch.test.js tests/chart_indicator.test.js tests/chart_history.test.js tests/update.test.js",
    "test:cli": "node --test tests/cli.test.js",
    "test:all": "node --test tests/e2e.test.js tests/pine_analyze.test.js tests/cli.test.js tests/sanitization.test.js tests/replay.test.js tests/launch.test.js tests/chart_indicator.test.js tests/chart_history.test.js tests/update.test.js",
    "test:verbose": "node --test --test-reporter=spec tests/e2e.test.js tests/pine_analyze.test.js",
    "test:count": "node --test --test-reporter=spec tests/e2e.test.js 2>&1 | tail -5"
  },
  "dependencies": {
    "@modelcontextprotocol/sdk": "^1.12.1",
    "chrome-remote-interface": "^0.33.2"
  },
  "devDependencies": {
    "eslint": "^9.39.4"
  }
}
